<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Models\Category; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\Support\Str; use Illuminate\Validation\Rule; use Illuminate\View\View;
class CategoryController extends Controller { public function index(): View { return view('admin.categories.index',['categories'=>Category::orderBy('name')->paginate(50)]); } public function store(Request $request): RedirectResponse { $data=$request->validate(['name'=>['required','string','max:255'],'slug'=>['nullable','string','max:255',Rule::unique('categories','slug')],'description'=>['nullable','string']]); $data['slug']=Str::slug($data['slug']?:$data['name']); Category::create($data); return back()->with('status','Category created.'); } }
